# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def patient_alice():
    return Patient(
        patient_id="patient-001",
        name="Alice Smith",
        date_of_birth="1985-06-15",
    )


@pytest.fixture
def patient_bob():
    return Patient(
        patient_id="patient-002",
        name="Bob Jones",
        date_of_birth="1972-11-30",
    )


@pytest.fixture
def patient_carol():
    """A patient not assigned to any clinician under test."""
    return Patient(
        patient_id="patient-003",
        name="Carol White",
        date_of_birth="1990-03-22",
    )


@pytest.fixture
def clinician_dr_green(patient_alice, patient_bob):
    """Clinician assigned to Alice and Bob, but NOT Carol."""
    return Clinician(
        clinician_id="clinician-101",
        name="Dr. Green",
        assigned_patient_ids=[patient_alice.patient_id, patient_bob.patient_id],
    )


@pytest.fixture
def clinician_dr_patel(patient_carol):
    """Clinician assigned only to Carol."""
    return Clinician(
        clinician_id="clinician-102",
        name="Dr. Patel",
        assigned_patient_ids=[patient_carol.patient_id],
    )


@pytest.fixture
def clinician_no_patients():
    """Clinician with an empty assignment list."""
    return Clinician(
        clinician_id="clinician-103",
        name="Dr. New",
        assigned_patient_ids=[],
    )


@pytest.fixture
def patient_repository(patient_alice, patient_bob, patient_carol):
    repo = MagicMock()

    patient_store = {
        patient_alice.patient_id: patient_alice,
        patient_bob.patient_id: patient_bob,
        patient_carol.patient_id: patient_carol,
    }

    repo.find_by_id.side_effect = lambda pid: patient_store.get(pid)
    return repo


@pytest.fixture
def assignment_repository(clinician_dr_green, clinician_dr_patel, clinician_no_patients):
    repo = MagicMock()

    all_clinicians = [clinician_dr_green, clinician_dr_patel, clinician_no_patients]
    assignment_map = {
        c.clinician_id: set(c.assigned_patient_ids) for c in all_clinicians
    }

    def is_assigned(clinician_id: str, patient_id: str) -> bool:
        return patient_id in assignment_map.get(clinician_id, set())

    repo.is_assigned.side_effect = is_assigned
    return repo


@pytest.fixture
def patient_service(patient_repository, assignment_repository):
    return PatientService(patient_repository, assignment_repository)


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def assert_patients_equal(actual: Patient, expected: Patient) -> None:
    assert actual.patient_id == expected.patient_id
    assert actual.name == expected.name
    assert actual.date_of_birth == expected.date_of_birth


# ---------------------------------------------------------------------------
# Tests: Authorised access (positive path)
# ---------------------------------------------------------------------------

class TestAuthorisedAccess:
    """Clinician reads a patient resource for a patient in their care."""

    def test_clinician_reads_assigned_patient_returns_patient(
        self, patient_service, clinician_dr_green, patient_alice
    ):
        """Happy path: assigned clinician retrieves expected patient object."""
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert_patients_equal(result, patient_alice)

    def test_clinician_reads_second_assigned_patient_returns_patient(
        self, patient_service, clinician_dr_green, patient_bob
    ):
        """Clinician with multiple assignments can read each assigned patient."""
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_bob.patient_id
        )
        assert_patients_equal(result, patient_bob)

    def test_second_clinician_reads_their_assigned_patient(
        self, patient_service, clinician_dr_patel, patient_carol
    ):
        """Different clinician can read their own assigned patient."""
        result = patient_service.read_patient(
            clinician_dr_patel.clinician_id, patient_carol.patient_id
        )
        assert_patients_equal(result, patient_carol)

    def test_read_patient_returns_correct_patient_id(
        self, patient_service, clinician_dr_green, patient_alice
    ):
        """Returned resource patient_id matches the requested patient_id."""
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert result.patient_id == patient_alice.patient_id

    def test_read_patient_returns_correct_name(
        self, patient_service, clinician_dr_green, patient_alice
    ):
        """Returned resource contains the correct patient name."""
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert result.name == patient_alice.name

    def test_read_patient_returns_correct_date_of_birth(
        self, patient_service, clinician_dr_green, patient_alice
    ):
        """Returned resource contains the correct date of birth."""
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert result.date_of_birth == patient_alice.date_of_birth

    def test_assignment_repository_is_consulted_on_authorised_read(
        self, patient_service, assignment_repository, clinician_dr_green, patient_alice
    ):
        """Access-control layer is always invoked, even for authorised requests."""
        patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assignment_repository.is_assigned.assert_called_once_with(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )

    def test_patient_repository_queried_after_authorisation(
        self, patient_service, patient_repository, clinician_dr_green, patient_alice
    ):
        """Patient data is only fetched after authorisation succeeds."""
        patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        patient_repository.find_by_id.assert_called_once_with(patient_alice.patient_id)


# ---------------------------------------------------------------------------
# Tests: Unauthorised access (negative path)
# ---------------------------------------------------------------------------

class TestUnauthorisedAccess:
    """Clinician is denied when reading a patient outside their assignment."""

    def test_clinician_cannot_read_unassigned_patient_raises_access_denied(
        self, patient_service, clinician_dr_green, patient_carol
    ):
        """Core denial: clinician reads a patient not in their care."""
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )

    def test_access_denied_error_message_contains_clinician_id(
        self, patient_service, clinician_dr_green, patient_carol
    ):
        """Error message identifies the clinician that was denied."""
        with pytest.raises(AccessDeniedError, match=clinician_dr_green.clinician_id):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )

    def test_access_denied_error_message_contains_patient_id(
        self, patient_service, clinician_dr_green, patient_carol
    ):
        """Error message identifies the patient that was requested."""
        with pytest.raises(AccessDeniedError, match=patient_carol.patient_id):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )

    def test_clinician_b_cannot_read_clinician_a_patient(
        self, patient_service, clinician_dr_patel, patient_alice
    ):
        """Cross-clinician access is denied (Dr. Patel cannot read Alice)."""
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_dr_patel.clinician_id, patient_alice.patient_id
            )

    def test_clinician_with_no_assignments_cannot_read_any_patient(
        self, patient_service, clinician_no_patients, patient_alice
    ):
        """Clinician with empty assignment list is denied for every patient."""
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_no_patients.clinician_id, patient_alice.patient_id
            )

    def test_unknown_clinician_id_is_denied(
        self, patient_service, patient_alice
    ):
        """A clinician ID that does not exist in the system is denied."""
        unknown_clinician_id = "clinician-UNKNOWN"
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(unknown_clinician_id, patient_alice.patient_id)

    def test_patient_repository_not_queried_when_access_denied(
        self, patient_service, patient_repository, clinician_dr_green, patient_carol
    ):
        """Patient data must never be fetched when access is denied (no data leak)."""
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )
        patient_repository.find_by_id.assert_not_called()

    def test_access_denied_is_subclass_of_permission_error(
        self, patient_service, clinician_dr_green, patient_carol
    ):
        """AccessDeniedError must be a PermissionError for standard exception handling."""
        with pytest.raises(PermissionError):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )

    def test_denial_is_not_patient_not_found(
        self, patient_service, clinician_dr_green, patient_carol
    ):
        """Access denial must not masquerade as a 'not found' response (no enumeration)."""
        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, patient_carol.patient_id
            )

    def test_empty_string_clinician_id_is_denied(
        self, patient_service, patient_alice
    ):
        """Empty-string clinician ID must be denied rather than cause an unhandled error."""
        with pytest.raises((AccessDeniedError, ValueError)):
            patient_service.read_patient("", patient_alice.patient_id)

    def test_empty_string_patient_id_is_denied(
        self, patient_service, clinician_dr_green
    ):
        """Empty-string patient ID must be denied rather than cause an unhandled error."""
        with pytest.raises((AccessDeniedError, ValueError)):
            patient_service.read_patient(clinician_dr_green.clinician_id, "")


# ---------------------------------------------------------------------------
# Tests: Edge cases
# ---------------------------------------------------------------------------

class TestEdgeCases:
    """Boundary and defensive scenarios."""

    def test_patient_not_found_for_authorised_clinician_raises_not_found(
        self, patient_service, clinician_dr_green
    ):
        """
        When a clinician IS assigned but the patient record does not exist,
        raise PatientNotFoundError (not AccessDeniedError).
        """
        ghost_patient_id = "patient-GHOST"
        # Temporarily grant assignment for a non-existent patient
        original_side_effect = patient_service._assignments.is_assigned.side_effect
        patient_service._assignments.is_assigned.side_effect = lambda cid, pid: (
            True if (cid == clinician_dr_green.clinician_id and pid == ghost_patient_id)
            else original_side_effect(cid, pid)
        )

        with pytest.raises(PatientNotFoundError):
            patient_service.read_patient(
                clinician_dr_green.clinician_id, ghost_patient_id
            )

    def test_clinician_assignment_reassigned_grants_access_to_new_patient(
        self, patient_service, assignment_repository, clinician_dr_green, patient_carol
    ):
        """
        After reassignment, clinician can read newly assigned patient.
        Simulates a dynamic care-team update.
        """
        # Extend the assignment map to include patient_carol
        original_side_effect = assignment_repository.is_assigned.side_effect
        assignment_repository.is_assigned.side_effect = lambda cid, pid: (
            True
            if (cid == clinician_dr_green.clinician_id and pid == patient_carol.patient_id)
            else original_side_effect(cid, pid)
        )

        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_carol.patient_id
        )
        assert result.patient_id == patient_carol.patient_id

    def test_read_same_patient_twice_succeeds_both_times(
        self, patient_service, clinician_dr_green, patient_alice
    ):
        """Repeated authorised reads are idempotent."""
        first = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        second = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert first.patient_id == second.patient_id

    def test_concurrent_read_attempts_each_checked_independently(
        self, patient_service, clinician_dr_green, clinician_dr_patel,
        patient_alice, patient_carol, assignment_repository
    ):
        """
        Interleaved calls for two clinicians are checked independently;
        one authorised call must not bleed into the other's context.
        """
        result = patient_service.read_patient(
            clinician_dr_green.clinician_id, patient_alice.patient_id
        )
        assert result.patient_id == patient_alice.patient_id

        with pytest.raises(AccessDeniedError):
            patient_service.read_patient(
                clinician_dr_patel.clinician_id, patient_alice.patient_id
            )

    @pytest.mark.parametrize("invalid_id", [None, 123, [], {}])
    def test_non_string_clinician_id_raises_error(
        self, patient_service, patient_alice, invalid_id
    ):
        """Non-string clinician IDs must raise an error, not silently pass."""
        with pytest.raises((AccessDeniedError, TypeError, ValueError, AttributeError)):
            patient_service.read_patient(invalid_id, patient_alice.patient_id)

    @pytest.mark.parametrize("invalid_id", [None, 123, [], {}])
    def test_non_string_patient_id_raises_error(
        self, patient_service, clinician_dr_green, invalid_id
    ):
        """Non-string patient IDs must raise an error, not silently pass."""
        with pytest.raises((AccessDeniedError, TypeError, ValueError, AttributeError)):
            patient_service.read_patient(clinician_dr_green.clinician_id, invalid_id)
```

---

## Test Summary

| Category | Test Count | Description |
|---|---|---|
| **Authorised Access** | 8 | Clinician reads patients within their care assignment |
| **Unauthorised Access** | 10 | Clinician denied when patient is outside their assignment |
| **Edge Cases** | 7 | Boundary, reassignment, idempotency, and type-safety scenarios |

## Key Design Decisions

| Decision | Rationale |
|---|---|
| **`AccessDeniedError` ≠ `PatientNotFoundError`**  | Prevents patient enumeration attacks — denial must not leak whether the patient even exists |
| **`patient_repository` not called on denial** | Ensures no data is fetched before authorisation passes (defence in depth) |
| **Assignment layer always consulted** | Verifies the authorisation check is never bypassed |
| **Parametrised invalid-ID tests** | Guards against type confusion and injection via unexpected input types |
| **Mocked repositories** | Isolates the access-control logic from infrastructure concerns |

